SELECT

FROM t_mibao_faq a


	a.del_flag = #{DEL_FLAG_NORMAL}
	${dataScope}

		AND a.title LIKE concat('%',#{title},'%')




		ORDER BY ${page.orderBy}


		ORDER BY a.sort

SELECT

FROM t_mibao_faq a


	a.del_flag = #{DEL_FLAG_NORMAL}
	${dataScope}



		ORDER BY ${page.orderBy}


		ORDER BY a.update_date DESC

mapper.update:
UPDATE t_mibao_faq SET
	sort = #{sort},
	title = #{title},
	update_date = #{updateDate}
WHERE id = #{id}

UPDATE t_mibao_faq SET
	del_flag = #{DEL_FLAG_DELETE}
WHERE id = #{id}

